// Tally payload → extract external_id and Fireflies meeting_id
const payload = items[0].json || {};
const fields = payload.body?.data?.fields || [];

// helper to get value by label or key
const byLabel = (label) => (fields.find(f => f.label === label) || {}).value;
const byKey   = (key)   => (fields.find(f => f.key   === key)   || {}).value;

const externalId =
  byLabel('Contract ID') || byKey('question_1VO594') || '';

const meetingUrl =
  byLabel('Meeting URL') || byKey('question_MRPyEE') || '';

// Basic validation
if (!externalId || !/^MID\d+$/i.test(externalId)) {
  throw new Error(`Invalid or missing Contract ID. Got: ${externalId || '(empty)'}`);
}
if (!meetingUrl) {
  throw new Error('Missing Meeting URL');
}

// Extract Fireflies meetingId from URL
function extractMeetingId(url) {
  // Example forms:
  // https://app.fireflies.ai/view/Verisk-New-North-Weekly-Meeting::01K9ADQAS9HMSYHZ0AM173J6KE
  // https://app.fireflies.ai/view/ASxwZxCstx
  // https://app.fireflies.ai/share/ASxwZxCstx
  let m;

  // form with ::ID at end
  m = url.match(/::([A-Za-z0-9]+)/);
  if (m) return m[1];

  // /view/<ID> or /share/<ID> or /meeting/<ID>
  m = url.match(/\/(?:view|share|meeting)\/([A-Za-z0-9]+)/);
  if (m) return m[1];

  // fallback: last alphanumeric chunk
  m = url.match(/\/([A-Za-z0-9]{8,})$/);
  if (m) return m[1];

  return null;
}

const meetingId = extractMeetingId(meetingUrl);
if (!meetingId) {
  throw new Error(`Could not parse meeting ID from URL: ${meetingUrl}`);
}

return [{ json: { external_id: externalId, meeting_id: meetingId, meeting_url: meetingUrl, raw_form: payload } }];

// Normalize Fireflies transcript → Supabase RPC payload
const resp = items[0].json || {};
const tr = resp.data?.transcript || {};
if (!tr.id) { throw new Error('Missing transcript'); }

const src = $item(0).$node['Format Tally Form data'].json; // rename if your first node has a different name

// Participants: emails from `participants` (handles comma-joined first entry) + speaker names
function normalizeEmails(arr) {
  const parts = (arr || [])
    .flatMap(v => (typeof v === 'string' ? v.split(',') : []))
    .map(s => s.trim())
    .filter(Boolean);
  return Array.from(new Set(parts));
}

const emails = normalizeEmails(tr.participants);
const speakerNames = (tr.speakers || []).map(s => s.name).filter(Boolean);
const participants = (speakerNames.length ? speakerNames : emails);

// Duration: Fireflies `duration` is minutes (float). Convert to seconds.
let durationSeconds = null;
if (typeof tr.duration === 'number' && !Number.isNaN(tr.duration)) {
  durationSeconds = Math.round(tr.duration * 60);
}

return [{
  json: {
    external_id: src.external_id,
    meeting_id: tr.id,
    meeting_url: tr.transcript_url || src.meeting_url,
    meeting_ts: tr.dateString || new Date().toISOString(),
    participants,
    duration_seconds: durationSeconds,
    recording_url: tr.audio_url || tr.meeting_link || null, // use if you later request audio_url
    transcript: tr,                  // store full structured transcript
    raw_metadata: resp               // original response
  }
}];

// Build "Speaker: text" lines (optionally with timestamps)
const tr = $item(0).$node['Format Fireflies Transcript Data'].json.transcript || {};
const sentences = Array.isArray(tr.sentences) ? tr.sentences : [];

function sToMmSs(v){ if(typeof v!=='number') return ''; const m=Math.floor(v/60), s=Math.round(v%60).toString().padStart(2,'0'); return `${m}:${s}`; }

const lines = sentences.map(s => {
  const who = s.speaker_name || 'Unknown';
  const t = s.text || '';
  const ts = s.start_time != null ? `[${sToMmSs(s.start_time)}] ` : '';
  return `${ts}${who}: ${t}`;
});

const labeled = lines.join('\n');

// Optional: cap or chunk for model limits (keep ~8–12k chars per chunk)
const MAX = 9000;
const chunks = [];
let buf = '';
for (const line of lines) {
  if ((buf + line + '\n').length > MAX) { chunks.push(buf); buf = ''; }
  buf += line + '\n';
}
if (buf) chunks.push(buf);

return [{ json: { transcript_labeled: labeled, transcript_chunks: chunks } }];

// Parse LLM JSON string from common shapes and shape for DB (no regex)

function getText(p) {
  if (typeof p === 'string') return p;
  if (p && typeof p.text === 'string') return p.text;
  // Claude/OpenAI via n8n (what your run shows):
  if (Array.isArray(p?.output) && p.output[0]?.content?.[0]?.text)
    return p.output[0].content[0].text;
  // Fallback: plain content array
  if (Array.isArray(p?.content) && p.content[0]?.text)
    return p.content[0].text;
  return '';
}

const raw = getText($json) || '';
let t = String(raw).trim();

// Strip any surrounding junk by taking the largest {...} block
const start = t.indexOf('{');
const end = t.lastIndexOf('}');
let parsed = {};
if (start !== -1 && end !== -1) {
  const slice = t.slice(start, end + 1);
  try { parsed = JSON.parse(slice); } catch { parsed = {}; }
}

const now = new Date().toISOString();
const label = ['positive','neutral','negative'].includes(parsed.label) ? parsed.label : 'neutral';
const confidence = Math.max(0, Math.min(1, Number(parsed.confidence ?? 0.6)));
const bullets = Array.isArray(parsed.bullets) ? parsed.bullets.slice(0, 5) : [];
const highlights = Array.isArray(parsed.highlights) ? parsed.highlights.slice(0, 3) : [];
const topics = Array.isArray(parsed.topics) ? parsed.topics.slice(0, 6) : [];

return [{
  json: {
    sentiment: {
      label,
      confidence,
      bullets,
      highlights,
      topics,
      model: parsed.model || 'openai/gpt-4-turbo',
      version: 1,
      generated_at: parsed.generated_at || now
    },
    // Helpful for debugging if something is empty:
    _raw_llm: raw
  }
}];
